7	fn scroll_to(section_id: &str) -> Callback<MouseEvent> {
8	    let id = section_id.to_string();
9	    Callback::from(move |e: MouseEvent| {
10	        e.prevent_default();
11	        if let Some(window) = web_sys::window()
12	            && let Some(doc) = window.document()
13	            && let Some(el) = doc.get_element_by_id(&id)
14	        {
15	            let el: &HtmlElement = el.dyn_ref().unwrap();
16	            el.scroll_into_view();
17	        }
18	    })
19	}
